util_js = """// Small 2D vector utilities using plain objects {x,y}
export function vec(x=0,y=0){return {x, y};}
export function add(a,b){return {x: a.x + b.x, y: a.y + b.y};}
export function sub(a,b){return {x: a.x - b.x, y: a.y - b.y};}
export function mul(v,s){return {x: v.x * s, y: v.y * s};}
export function div(v,s){return {x: v.x / s, y: v.y / s};}
export function mag(v){return Math.hypot(v.x, v.y);}
export function mag2(v){return v.x*v.x + v.y*v.y;}
export function normalize(v){let m = mag(v)||1; return {x: v.x/m, y: v.y/m};}
export function limit(v, max){ let m = mag(v); if (m > max) return mul(normalize(v), max); return v; }
export function dist2(a,b){ let dx = a.x-b.x, dy = a.y-b.y; return dx*dx + dy*dy; }
export function randRange(a,b){ return a + Math.random()*(b-a); }
export function clamp(v, a, b){ return Math.max(a, Math.min(b, v)); }
export function hueColor(h, s='80%', l='55%'){ return `hsl(${h} ${s} ${l})`; }
"""

boid_js = """import { vec, add, sub, div, mul, mag, normalize, limit, dist2, randRange, hueColor } from './util.js';

export class Boid {
  constructor(x, y, w, h, id=0) {
    this.pos = vec(x !== undefined ? x : Math.random()*w, y !== undefined ? y : Math.random()*h);
    // velocity randomized for fast motion
    const ang = Math.random()*Math.PI*2;
    this.vel = vec(Math.cos(ang)*randRange(1.5,4.0), Math.sin(ang)*randRange(1.5,4.0));
    this.acc = vec(0,0);
    this.id = id;
    this.w = w;
    this.h = h;
    // tuned parameters for a lively, fast swarm
    this.maxSpeed = randRange(3.0, 5.5);
    this.maxForce = 0.05;
    this.perception = 48;        // for alignment/cohesion
    this.sepPerception = 26;     // for separation
    this.hue = (id * 37) % 360;  // varying hue per boid id
  }

  applyForce(f) {
    this.acc = add(this.acc, f);
  }

  edges() {
    // wrap-around edges
    if (this.pos.x < 0) this.pos.x += this.w;
    if (this.pos.y < 0) this.pos.y += this.h;
    if (this.pos.x >= this.w) this.pos.x -= this.w;
    if (this.pos.y >= this.h) this.pos.y -= this.h;
  }

  align(boids) {
    let steering = vec(0,0), total = 0;
    for (let other of boids) {
      if (other === this) continue;
      let d2 = dist2(this.pos, other.pos);
      if (d2 < this.perception*this.perception) {
        steering = add(steering, other.vel);
        total++;
      }
    }
    if (total > 0) {
      steering = div(steering, total);
      steering = normalize(steering);
      steering = mul(steering, this.maxSpeed);
      steering = sub(steering, this.vel);
      steering = limit(steering, this.maxForce);
    }
    return steering;
  }

  cohesion(boids) {
    let steering = vec(0,0), total = 0;
    for (let other of boids) {
      if (other === this) continue;
      let d2 = dist2(this.pos, other.pos);
      if (d2 < this.perception*this.perception) {
        steering = add(steering, other.pos);
        total++;
      }
    }
    if (total > 0) {
      steering = div(steering, total);
      steering = sub(steering, this.pos);
      steering = normalize(steering);
      steering = mul(steering, this.maxSpeed);
      steering = sub(steering, this.vel);
      steering = limit(steering, this.maxForce);
    }
    return steering;
  }

  separation(boids) {
    let steering = vec(0,0), total = 0;
    for (let other of boids) {
      if (other === this) continue;
      let dx = this.pos.x - other.pos.x;
      let dy = this.pos.y - other.pos.y;
      let d2 = dx*dx + dy*dy;
      if (d2 < this.sepPerception*this.sepPerception && d2 > 0) {
        let diff = vec(dx, dy);
        let inv = 1 / Math.sqrt(d2);
        diff = mul(diff, inv); // normalize
        diff = div(diff, Math.sqrt(d2)); // stronger when closer
        steering = add(steering, diff);
        total++;
      }
    }
    if (total > 0) {
      steering = div(steering, total);
      steering = normalize(steering);
      steering = mul(steering, this.maxSpeed);
      steering = sub(steering, this.vel);
      steering = limit(steering, this.maxForce * 1.5);
    }
    return steering;
  }

  flock(boids) {
    // weights chosen for vivid, slightly chaotic flocking
    const align = this.align(boids);
    const coh = this.cohesion(boids);
    const sep = this.separation(boids);
    this.applyForce(mul(align, 1.0));
    this.applyForce(mul(coh, 0.7));
    this.applyForce(mul(sep, 1.6));
  }

  update() {
    this.vel = add(this.vel, this.acc);
    this.vel = limit(this.vel, this.maxSpeed);
    this.pos = add(this.pos, this.vel);
    this.acc = vec(0,0);
  }

  draw(ctx) {
    // Draw as a rotated triangle pointing in velocity direction
    const angle = Math.atan2(this.vel.y, this.vel.x);
    ctx.save();
    ctx.translate(this.pos.x, this.pos.y);
    ctx.rotate(angle);
    // color reacts to speed for dynamic hues
    const speed = mag(this.vel);
    const hue = (this.hue + speed*18) % 360;
    ctx.fillStyle = hueColor(hue, '75%', '55%');
    ctx.beginPath();
    ctx.moveTo(10, 0);
    ctx.lineTo(-6, 4);
    ctx.lineTo(-6, -4);
    ctx.closePath();
    ctx.fill();
    ctx.restore();
  }
}
"""

script_js = """import { Boid } from './boid.js';
import { vec, randRange } from './util.js';

const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d', { alpha: false });

let W = canvas.width = window.innerWidth;
let H = canvas.height = window.innerHeight;

let boids = [];
let running = true;
let targetCount = 400;
const defaults = { count: 400 };

const countSlider = document.getElementById('countSlider');
const countLabel = document.getElementById('countLabel');
const toggleBtn = document.getElementById('toggleBtn');
const fpsLabel = document.getElementById('fps');

function resize() {
  W = canvas.width = window.innerWidth;
  H = canvas.height = window.innerHeight;
  // update boid boundaries
  for (let b of boids) { b.w = W; b.h = H; }
}
window.addEventListener('resize', resize);

function makeBoid(i) {
  return new Boid(Math.random()*W, Math.random()*H, W, H, i);
}

function populate(n) {
  boids = [];
  for (let i=0;i<n;i++) boids.push(makeBoid(i));
}

countSlider.addEventListener('input', (e) => {
  targetCount = parseInt(e.target.value, 10);
  countLabel.textContent = targetCount;
});

countSlider.addEventListener('change', (e) => {
  // re-create to reset ids and distribution
  populate(targetCount);
});

toggleBtn.addEventListener('click', () => {
  running = !running;
  toggleBtn.textContent = running ? 'Pause' : 'Play';
});

populate(defaults.count);
countLabel.textContent = defaults.count;
countSlider.value = defaults.count;

let last = performance.now();
let fps = 0;
let frames = 0;
let acum = 0;

function step(now) {
  const dt = Math.min(50, now - last); // clamp delta
  last = now;
  if (running) {
    // update
    for (let b of boids) {
      b.flock(boids);
      b.update();
      b.edges();
    }
  }

  // draw background
  // clear with a slightly darkened rectangle for trailing effect:
  ctx.fillStyle = '#071019';
  ctx.fillRect(0,0,W,H);

  // draw boids
  for (let b of boids) b.draw(ctx);

  // FPS calc
  frames++;
  acum += dt;
  if (acum >= 250) {
    fps = Math.round(frames / (acum/1000));
    frames = 0;
    acum = 0;
    fpsLabel.textContent = `FPS: ${fps}`;
    // also show count
    countLabel.textContent = boids.length;
  }

  requestAnimationFrame(step);
}

// start the loop
requestAnimationFrame(step);

// expose a global helper for quick debugging in the console
window.boids_sim = {
  setCount(n) { populate(n); targetCount = n; countSlider.value = n; countLabel.textContent = n; },
  pause() { running = false; toggleBtn.textContent = 'Play'; },
  play() { running = true; toggleBtn.textContent = 'Pause'; },
  list() { return boids; }
};
"""

